#!/usr/bin/env Rscript
#
# code/04_render_report.R
#
# Task T028: Generate the final HTML/PDF analysis report.
#
# This script renders the RMarkdown report (code/04_report.Rmd) using
# the processed data artifacts generated by previous pipeline stages.
#
# Dependencies:
# - code/04_report.Rmd (must exist)
# - data/derived/classified_data.csv (from T012)
# - data/derived/ancova_results.csv (from T019)
# - data/derived/effect_sizes.csv (from T019)
# - data/derived/reliability_metrics.csv (from T018)
# - data/derived/sensitivity_sweep.csv (from T027)
# - data/derived/exclusion_counts.json (from T012.5)
#
# Output:
# - reports/chronotype_moral_analysis.html (or .pdf)

library(rmarkdown)
library(dplyr)
library(readr)
library(jsonlite)
library(lubridate)

# Configuration
PROJECT_ROOT <- normalizePath(".")
RMD_PATH <- file.path(PROJECT_ROOT, "code", "04_report.Rmd")
OUTPUT_DIR <- file.path(PROJECT_ROOT, "reports")
OUTPUT_HTML <- file.path(OUTPUT_DIR, "chronotype_moral_analysis.html")

# Ensure output directory exists
if (!dir.exists(OUTPUT_DIR)) {
  dir.create(OUTPUT_DIR, recursive = TRUE)
}

# Verify input artifacts exist before rendering
required_files <- c(
  "data/derived/classified_data.csv",
  "data/derived/ancova_results.csv",
  "data/derived/effect_sizes.csv",
  "data/derived/reliability_metrics.csv",
  "data/derived/sensitivity_sweep.csv",
  "data/derived/exclusion_counts.json"
)

missing_files <- c()
for (f in required_files) {
  full_path <- file.path(PROJECT_ROOT, f)
  if (!file.exists(full_path)) {
    missing_files <- c(missing_files, f)
  }
}

if (length(missing_files) > 0) {
  stop(paste(
    "Cannot render report. Missing required input artifacts:\n",
    paste(missing_files, collapse = "\n- "),
    "\nPlease ensure previous pipeline stages (T012, T018, T019, T027) have completed successfully."
  ))
}

if (!file.exists(RMD_PATH)) {
  stop(paste("RMarkdown template not found at:", RMD_PATH))
}

# Render the report
# We use 'html_document' as the default format.
# If PDF is required, the .Rmd file should be configured for 'pdf_document'.
# The script ensures the output path matches the task requirement.

cat("Rendering report: ", RMD_PATH, "\n")
cat("Output destination: ", OUTPUT_HTML, "\n")

tryCatch({
  render(
    input = RMD_PATH,
    output_file = "chronotype_moral_analysis.html",
    output_dir = OUTPUT_DIR,
    output_format = "html_document",
    quiet = FALSE
  )

  # Verify output was created
  if (file.exists(OUTPUT_HTML)) {
    cat("SUCCESS: Report generated at ", OUTPUT_HTML, "\n")
  } else {
    stop("Render completed but output file was not found.")
  }

}, error = function(e) {
  cat("ERROR during rendering:\n")
  print(e)
  stop("Report generation failed.")
})
